import React, { useEffect, useRef, useState, useMemo } from 'react';
import { useChat } from '../context/ChatContext';
import { useAuth } from '../context/AuthContext';
import MessageInput from './MessageInput';
import VideoCall from './VideoCall';
import './ChatWindow.css';

const ChatWindow = () => {
  const { selectedUser, messages, typing, markAsRead } = useChat();
  const { user } = useAuth();
  const [showVideoCall, setShowVideoCall] = useState(false);

  const chatMessages = selectedUser ? messages[selectedUser._id] || [] : [];
  const isTyping = selectedUser && typing[selectedUser._id];
  const messagesEndRef = useRef(null);

  // Generate a consistent roomId for private chat between two users
  const roomId = useMemo(() => {
    if (!selectedUser || !user) return null;
    const ids = [user._id, selectedUser._id].sort();
    return `private_${ids[0]}_${ids[1]}`;
  }, [selectedUser, user]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatMessages]);

  // Mark messages as read when viewing a conversation
  useEffect(() => {
    if (selectedUser) {
      markAsRead(selectedUser._id);
    }
  }, [selectedUser, chatMessages, markAsRead]);

  const parseMediaMessage = (text) => {
    if (typeof text !== 'string') return null;
    if (!text.startsWith('__media__:')) return null;

    const parts = text.split(':');
    if (parts.length < 3) return null;

    const mediaType = parts[1];
    const url = parts.slice(2).join(':');
    return { mediaType, url };
  };

  if (!selectedUser) {
    return (
      <div className="chat-window empty">
        <div className="empty-state">
          <h3>Select a user to start chatting</h3>
          <p>Choose someone from the online users list</p>
        </div>
      </div>
    );
  }

  return (
    <div className="chat-window">
      <div className="chat-window-header">
        <div className="chat-user-info">
          <div className="chat-user-avatar">
            {selectedUser.nickname.charAt(0).toUpperCase()}
          </div>
          <div>
            <h4>{selectedUser.nickname}</h4>
            <span className={`gender-badge ${selectedUser.gender?.toLowerCase()}`}>
              {selectedUser.gender}
            </span>
          </div>
        </div>
        <div className="header-actions">
          <button 
            className="video-call-btn"
            onClick={() => setShowVideoCall(!showVideoCall)}
            title={showVideoCall ? 'Hide Video Call' : 'Start Video Call'}
          >
            📹 {showVideoCall ? 'Hide' : 'Video'}
          </button>
        </div>
      </div>

      {showVideoCall && (
        <div className="video-call-section">
          <VideoCall 
            partner={selectedUser}
            roomId={roomId}
            onEndCall={() => setShowVideoCall(false)}
          />
        </div>
      )}

      <div className="messages-container">
        {chatMessages.map((msg, index) => {
          const media = parseMediaMessage(msg.text);
          return (
            <div
              key={index}
              className={`message ${msg.from === user._id ? 'sent' : 'received'}`}
            >
              {media ? (
                <div className="message-media">
                  {media.mediaType === 'video' ? (
                    <video controls src={media.url} />
                  ) : (
                    <img src={media.url} alt="Upload" />
                  )}
                </div>
              ) : (
                <p>{msg.text}</p>
              )}
              <span className="message-time">
                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          );
        })}
        {isTyping && (
          <div className="typing-indicator">
            <span>{selectedUser.nickname} is typing...</span>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <MessageInput />
    </div>
  );
};

export default ChatWindow;
